<?php
/**
 * AdminBeautify 插件自动更新器
 *
 * 支持在主版本号和次版本号相同时（如 2.1.x）自动下载并应用补丁更新，
 * 跨次版本更新则引导用户前往 GitHub 手动下载。
 *
 * @package AdminBeautify
 * @author LHL
 * @version 2.1.0
 * @link https://github.com/lhl77/Typecho-Plugin-AdminBeautify
 */
 
 if(!defined('__TYPECHO_ROOT_DIR__')){exit;}class AdminBeautify_Updater{const GITHUB_REPO='lhl77/Typecho-Plugin-AdminBeautify';const GITHUB_API_RELEASES='https://api.github.com/repos/lhl77/Typecho-Plugin-AdminBeautify/releases/latest';const GITHUB_RELEASES_PAGE='https://github.com/lhl77/Typecho-Plugin-AdminBeautify/releases';const CURRENT_VERSION='2.1.0';private $c;private $d;public function __construct(){$e->pluginDir=rtrim(dirname(__FILE__),'/\\');$e->tmpDir=$e->pluginDir.'/tmp_update';}public function fetchLatestRelease(){$f=$e->httpGet(self::GITHUB_API_RELEASES);if($f===false)return false;$g=@json_decode($f,true);if(!is_array($g)||empty($g['tag_name']))return false;$h=ltrim($g['tag_name'],'vV');$j=isset($g['html_url'])?$g['html_url']:self::GITHUB_RELEASES_PAGE;$k=isset($g['body'])?$g['body']:'';$l='';if(!empty($g['assets'])&&is_array($g['assets'])){foreach($g['assets']as $m){if(isset($m['browser_download_url'])&&substr($m['browser_download_url'],-4)==='.zip'){$l=$m['browser_download_url'];break;}}}if($l===''&&!empty($g['zipball_url'])){$l=$g['zipball_url'];}return array('version'=>$h,'download_url'=>$l,'html_url'=>$j,'body'=>$k,);}public static function compareVersion($n,$o){$p=array_map('intval',explode('.',ltrim((string)$n,'vV')));$q=array_map('intval',explode('.',ltrim((string)$o,'vV')));$r=max(count($p),count($q));for($s=0;$s<$r;$s++){$t=isset($p[$s])?$p[$s]:0;$u=isset($q[$s])?$q[$s]:0;if($t>$u)return1;if($t<$u)return-1;}return0;}public static function canDirectUpdate($v,$w){$x=array_map('intval',explode('.',ltrim((string)$v,'vV')));$y=array_map('intval',explode('.',ltrim((string)$w,'vV')));while(count($x)<3)$x[]=0;while(count($y)<3)$y[]=0;return($x[0]===$y[0]&&$x[1]===$y[1]&&$y[2]>$x[2]);}public function doUpdate($l,$z){$aa=array();$aa[]='正在下载 '.$l.' ...';$bb=$e->httpGet($l);if($bb===false||strlen($bb)<100){return array('ok'=>false,'msg'=>'下载失败，请检查服务器网络或手动更新','details'=>$aa);}$aa[]='下载完成，大小 '.round(strlen($bb)/1024,1).' KB';if(!function_exists('zip_open')&&!class_exists('ZipArchive')){return array('ok'=>false,'msg'=>'服务器未安装 PHP zip 扩展，无法自动解压，请手动下载更新','details'=>$aa);}if(!is_dir($e->tmpDir)){@mkdir($e->tmpDir,0755,true);}$cc=$e->tmpDir.'/update.zip';if(file_put_contents($cc,$bb)===false){return array('ok'=>false,'msg'=>'无法写入临时文件，请检查目录权限','details'=>$aa);}$aa[]='已保存临时 ZIP';$dd=$e->tmpDir.'/extracted';if(is_dir($dd))$e->removeDir($dd);@mkdir($dd,0755,true);if(class_exists('ZipArchive')){$ee=new ZipArchive();$ff=$ee->open($cc);if($ff!==true){$e->cleanup();return array('ok'=>false,'msg'=>'无法打开 ZIP 文件（ZipArchive 错误 '.$ff.'）','details'=>$aa);}$ee->extractTo($dd);$ee->close();}else{$gg=zip_open($cc);if(!is_resource($gg)){$e->cleanup();return array('ok'=>false,'msg'=>'无法打开 ZIP 文件','details'=>$aa);}while($hh=zip_read($gg)){$ii=zip_entry_name($hh);$jj=$dd.'/'.$ii;if(substr($ii,-1)==='/'){@mkdir($jj,0755,true);}else{@mkdir(dirname($jj),0755,true);if(zip_entry_open($gg,$hh)){file_put_contents($jj,zip_entry_read($hh,zip_entry_filesize($hh)));zip_entry_close($hh);}}}zip_close($gg);}$aa[]='解压完成';$kk=$e->findPluginRoot($dd);if($kk===false){$e->cleanup();return array('ok'=>false,'msg'=>'在 ZIP 中找不到插件文件，请手动更新','details'=>$aa);}$aa[]='插件根目录：'.str_replace($dd,'',$kk);$ll=$e->tmpDir.'/backup_'.self::CURRENT_VERSION;if(!is_dir($ll))@mkdir($ll,0755,true);$e->copyDir($e->pluginDir,$ll,array('tmp_update'));$aa[]='已备份当前版本到 tmp_update/backup_'.self::CURRENT_VERSION;$mm=array('tmp_update','assets/compat');$nn=$e->copyDir($kk,$e->pluginDir,$mm);$aa[]='已覆盖 '.$nn.' 个文件';@unlink($cc);$e->removeDir($dd);$aa[]='临时文件已清理';return array('ok'=>true,'msg'=>'更新成功！已从 v'.self::CURRENT_VERSION.' 更新至 v'.$z.'，请刷新页面。','details'=>$aa);}private function findPluginRoot($oo){if(file_exists($oo.'/Plugin.php'))return $oo;$pp=@scandir($oo);if($pp){foreach($pp as $qq){if($qq==='.'||$qq==='..')continue;$rr=$oo.'/'.$qq;if(is_dir($rr)&&file_exists($rr.'/Plugin.php'))return $rr;}}return false;}private function copyDir($ss,$tt,$mm=array()){$uu=0;if(!is_dir($tt))@mkdir($tt,0755,true);$pp=@scandir($ss);if(!$pp)return0;foreach($pp as $qq){if($qq==='.'||$qq==='..')continue;$vv=$ss.'/'.$qq;$ww=$tt.'/'.$qq;$xx=false;foreach($mm as $yy){$zz=basename($yy);if($qq===$zz){$xx=true;break;}}if($xx)continue;if(is_dir($vv)){$uu+=$e->copyDir($vv,$ww,$mm);}else{if(copy($vv,$ww))$uu++;}}return $uu;}private function removeDir($oo){if(!is_dir($oo))return;$pp=@scandir($oo);if($pp){foreach($pp as $qq){if($qq==='.'||$qq==='..')continue;$aaa=$oo.'/'.$qq;if(is_dir($aaa))$e->removeDir($aaa);else@unlink($aaa);}}@rmdir($oo);}private function cleanup(){@unlink($e->tmpDir.'/update.zip');$dd=$e->tmpDir.'/extracted';if(is_dir($dd))$e->removeDir($dd);}private function httpGet($bbb){$ccc=array('http'=>array('method'=>'GET','timeout'=>30,'header'=>"User-Agent: AdminBeautify-Updater/".self::CURRENT_VERSION."\r\n"."Accept: application/vnd.github.v3+json\r\n",'follow_location'=>1,),'ssl'=>array('verify_peer'=>false,'verify_peer_name'=>false,),);$ddd=stream_context_create($ccc);$eee=@file_get_contents($bbb,false,$ddd);if($eee!==false)return $eee;if(!function_exists('curl_init'))return false;$fff=curl_init($bbb);curl_setopt_array($fff,array(CURLOPT_RETURNTRANSFER=>true,CURLOPT_TIMEOUT=>30,CURLOPT_FOLLOWLOCATION=>true,CURLOPT_SSL_VERIFYPEER=>false,CURLOPT_SSL_VERIFYHOST=>false,CURLOPT_USERAGENT=>'AdminBeautify-Updater/'.self::CURRENT_VERSION,CURLOPT_HTTPHEADER=>array('Accept: application/vnd.github.v3+json'),));$eee=curl_exec($fff);$ggg=curl_getinfo($fff,CURLINFO_HTTP_CODE);curl_close($fff);return($eee!==false&&$ggg>=200&&$ggg<400)?$eee:false;}}
